; Thermal comfort metrics are used to measure the perceived comfort level of a space based on factors such as temperature, humidity, and air movement; 
; Occupancy refers to the number of people present in a given space;
; A higher comfort score indicates a more comfortable zone.

sql:
SELECT zone_name, zone_elevation
FROM zones
WHERE zone_elevation = (SELECT MIN(zone_elevation) FROM zones);

SELECT AVG(value) AS average_air_velocity
FROM simulations
WHERE metric_id = (SELECT metric_id FROM thermal_comfort_metrics WHERE metric_name = 'Air Velocity');
